/**
 * FIXED: Unified Job Normalizer for ALL Sources
 *
 * Handles:
 *  - Google Jobs (SerpApi)
 *  - APIFY LinkedIn
 *  - APIFY Indeed
 *  - APIFY Naukri
 *  - Greenhouse ATS
 *  - Lever ATS
 *  - Generic fallback
 *
 * Version: 2.0 (Fixed)
 * Last Updated: 2026-01-28
 */

// ========== UTILITY FUNCTIONS ==========

function toStringSafe(v) {
  if (v === null || v === undefined) return ''
  if (typeof v === 'string') return v
  try {
    return String(v)
  } catch {
    return ''
  }
}

function decodeHtmlEntities(s) {
  const str = toStringSafe(s)
  if (!str) return ''
  const named = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&apos;': "'",
    '&#x2013;': '–',
    '&#x2014;': '—',
    '&#xA0;': ' ',
    '&nbsp;': ' ',
  }
  return str.replace(/&[a-zA-Z]+;|&#\d+;|&#x[0-9A-Fa-f]+;/g, (m) => {
    if (named[m] !== undefined) return named[m]
    if (m.startsWith('&#x')) {
      const cp = parseInt(m.slice(3, -1), 16)
      return isNaN(cp) ? m : String.fromCodePoint(cp)
    }
    if (m.startsWith('&#')) {
      const cp = parseInt(m.slice(2, -1), 10)
      return isNaN(cp) ? m : String.fromCodePoint(cp)
    }
    return m
  })
}

function stripHtml(s) {
  return toStringSafe(s).replace(/<\/?[^>]+(>|$)/g, ' ')
}

function cleanText(s) {
  const decoded = decodeHtmlEntities(s)
  const noTags = stripHtml(decoded)
  return noTags.replace(/\s+/g, ' ').trim()
}

function firstNonEmpty(...vals) {
  for (const v of vals) {
    const s = cleanText(v)
    if (s) return s
  }
  return ''
}

function getDateISOOrNow(input) {
  const s = toStringSafe(input).trim()
  if (!s) return new Date().toISOString()
  const d = new Date(s)
  return isNaN(d.getTime()) ? new Date().toISOString() : d.toISOString()
}

function parseRelativeTime(rel) {
  const s = toStringSafe(rel).toLowerCase().trim()
  if (!s) return null
  const now = new Date()

  // Match patterns like "3 days ago", "2 hours ago", "just now", "today"
  if (s.includes('just now') || s.includes('today')) {
    return now.toISOString()
  }

  const m = s.match(/(\d+)\s*(minute|hour|day|week|month|year)s?\s*ago/)
  if (!m) return null

  const amount = parseInt(m[1], 10)
  const unit = m[2]
  const d = new Date(now)

  switch (unit) {
    case 'minute':
      d.setMinutes(d.getMinutes() - amount)
      break
    case 'hour':
      d.setHours(d.getHours() - amount)
      break
    case 'day':
      d.setDate(d.getDate() - amount)
      break
    case 'week':
      d.setDate(d.getDate() - amount * 7)
      break
    case 'month':
      d.setMonth(d.getMonth() - amount)
      break
    case 'year':
      d.setFullYear(d.getFullYear() - amount)
      break
    default:
      return null
  }
  return d.toISOString()
}

function ensureUrlLike(s) {
  const v = toStringSafe(s).trim()
  if (!v) return ''
  if (/^(https?:\/\/|mailto:)/i.test(v)) return v
  if (/^[\w.-]+\.[a-z]{2,}($|\/)/i.test(v)) return 'https://' + v
  return ''
}

function simpleHash(str) {
  let hash = 0
  const s = toStringSafe(str)
  for (let i = 0; i < s.length; i++) {
    hash = (hash << 5) - hash + s.charCodeAt(i)
    hash |= 0
  }
  return Math.abs(hash).toString(36)
}

function buildExternalId(provider, raw, urlCandidate) {
  // Try to extract unique ID from various fields
  const ids = [
    raw.job_id,
    raw.jobId,
    raw.id,
    raw.external_id,
    raw.guid,
    raw.job_link_id,
  ]
    .map(toStringSafe)
    .filter(Boolean)

  if (ids.length > 0) return `${provider}_${ids[0]}`

  // Fallback: hash combination of key fields
  const seed = [
    provider,
    toStringSafe(raw.title || raw.positionName || raw.jobTitle),
    toStringSafe(
      raw.company_name || raw.company || raw.companyName || raw.employerName
    ),
    ensureUrlLike(
      urlCandidate || raw.apply_url || raw.apply_link || raw.url || raw.jobUrl
    ),
  ].join('||')

  return `${provider}_${simpleHash(seed || JSON.stringify(raw))}`
}

// ========== SOURCE DETECTION ==========

function detectJobSource(job) {
  if (!job || typeof job !== 'object') return 'unknown'

  // APIFY LinkedIn: Has companyName, applyUrl/jobUrl, often publishedAt
  if (
    job.companyName &&
    (job.applyUrl || job.jobUrl) &&
    (job.publishedAt || job.postedTime)
  ) {
    return 'apify_linkedin'
  }

  // APIFY Indeed: Has positionName, externalApplyLink
  if (job.positionName || job.externalApplyLink) {
    return 'apify_indeed'
  }

  // APIFY Naukri: Has jobTitle, specific structure
  if (job.jobTitle && job.companyName && !job.publishedAt) {
    return 'apify_naukri'
  }

  // Google Jobs (SerpApi): Has company_name, job_id, apply_options
  if (job.company_name || job.job_id || job.apply_options) {
    return 'google_jobs'
  }

  // Greenhouse: Has specific ATS structure
  if (job.departments || job.offices || job.gh_jid) {
    return 'greenhouse'
  }

  // Lever: Has specific ATS structure
  if (job.categories || job.lever_id) {
    return 'lever'
  }

  return 'generic'
}

// ========== NORMALIZERS (SOURCE-SPECIFIC) ==========

function normalizeFromGoogleJobs(job) {
  const title = cleanText(job.title)
  const company = firstNonEmpty(job.company_name, job.company)
  const location = firstNonEmpty(job.location, job.address, 'India')

  // Fallback chain for description
  let description = cleanText(job.description || job.snippet || job.highlights)
  if (!description && job.via) {
    description = `Job available ${job.via}. Click apply to view full details on the source site.`
  }

  // Apply URL priority
  const applyUrl = ensureUrlLike(
    (job.apply_options && job.apply_options[0] && job.apply_options[0].link) ||
      job.apply_link ||
      job.share_link ||
      job.apply_url ||
      job.url
  )

  // Better ID extraction for Google Jobs (try to find htidocid in URL)
  let extractedId = job.job_id || job.jobId
  if (!extractedId && applyUrl) {
    const match = applyUrl.match(/htidocid=([^&]+)/)
    if (match) extractedId = match[1]
  }

  // Parse posted date
  let postedDate = new Date().toISOString()
  if (job.detected_extensions && job.detected_extensions.posted_at) {
    const parsed = parseRelativeTime(job.detected_extensions.posted_at)
    postedDate = parsed || getDateISOOrNow(job.detected_extensions.posted_at)
  } else if (job.posted_at || job.date) {
    postedDate = getDateISOOrNow(job.posted_at || job.date)
  }

  return {
    title,
    company,
    location,
    description,
    apply_url: applyUrl,
    source: 'google_jobs',
    external_id: buildExternalId(
      'google_jobs',
      { ...job, job_id: extractedId },
      applyUrl
    ),
    posted_date: postedDate,
    salary:
      (job.detected_extensions && job.detected_extensions.salary) ||
      job.salary ||
      null,
    via: job.via || 'google_jobs',
  }
}

function normalizeFromApifyLinkedIn(job) {
  const title = cleanText(job.title)
  const company = firstNonEmpty(job.companyName, job.company)
  const location = firstNonEmpty(job.location, 'India')
  const description = firstNonEmpty(job.description, job.descriptionHtml)
  const applyUrl = ensureUrlLike(job.applyUrl || job.jobUrl || job.url)

  // Parse posted date
  let postedDate = new Date().toISOString()
  if (job.publishedAt) {
    postedDate = getDateISOOrNow(job.publishedAt)
  } else if (job.postedTime) {
    const parsed = parseRelativeTime(job.postedTime)
    postedDate = parsed || new Date().toISOString()
  }

  const out = {
    title,
    company,
    location,
    description: cleanText(description),
    apply_url: applyUrl,
    source: 'apify_linkedin', // FIXED: Was 'linkedin'
    external_id: buildExternalId('apify_linkedin', job, applyUrl),
    posted_date: postedDate,
    salary: cleanText(job.salary) || null,
    via: 'apify_linkedin',
  }

  // Add LinkedIn-specific metadata
  if (job.contractType) out.contract_type = cleanText(job.contractType)
  if (job.experienceLevel) out.experience_level = cleanText(job.experienceLevel)
  if (job.workType) out.work_type = cleanText(job.workType)
  if (job.sector) out.sector = cleanText(job.sector)

  return out
}

function normalizeFromApifyIndeed(job) {
  // APIFY Indeed specific fields
  const title = firstNonEmpty(job.positionName, job.position, job.title)
  const company = firstNonEmpty(job.company, job.employerName)
  const location = firstNonEmpty(job.location, job.city, 'India')
  const description = firstNonEmpty(job.description, job.summary)

  // APIFY Indeed uses 'url' or 'externalApplyLink'
  const applyUrl = ensureUrlLike(
    job.externalApplyLink || job.url || job.apply_url || job.link
  )

  // Parse posted date
  let postedDate = new Date().toISOString()
  if (job.postedAt || job.datePosted) {
    const parsed = parseRelativeTime(job.postedAt || job.datePosted)
    postedDate = parsed || getDateISOOrNow(job.postedAt || job.datePosted)
  }

  return {
    title: cleanText(title),
    company: cleanText(company),
    location: cleanText(location),
    description: cleanText(description),
    apply_url: applyUrl,
    source: 'apify_indeed',
    external_id: buildExternalId('apify_indeed', job, applyUrl),
    posted_date: postedDate,
    salary: cleanText(job.salary || job.pay) || null,
    via: 'apify_indeed',
  }
}

function normalizeFromApifyNaukri(job) {
  // APIFY Naukri specific fields
  const title = firstNonEmpty(job.jobTitle, job.title)
  const company = firstNonEmpty(job.companyName, job.company)
  const location = firstNonEmpty(job.jobLocation, job.location, 'India')
  const description = firstNonEmpty(job.jobDescription, job.description)

  // APIFY Naukri uses 'applyUrl'
  const applyUrl = ensureUrlLike(
    job.applyUrl || job.url || job.jobUrl || job.apply_url
  )

  // Parse posted date
  let postedDate = new Date().toISOString()
  if (job.postedDate || job.datePosted) {
    const parsed = parseRelativeTime(job.postedDate || job.datePosted)
    postedDate = parsed || getDateISOOrNow(job.postedDate || job.datePosted)
  }

  return {
    title: cleanText(title),
    company: cleanText(company),
    location: cleanText(location),
    description: cleanText(description),
    apply_url: applyUrl,
    source: 'apify_naukri',
    external_id: buildExternalId('apify_naukri', job, applyUrl),
    posted_date: postedDate,
    salary: cleanText(job.salary || job.pay) || null,
    via: 'apify_naukri',
  }
}

function normalizeGenericJob(job, providerHint = 'generic') {
  const title = firstNonEmpty(
    job.title,
    job.position,
    job.jobTitle,
    job.positionName
  )
  const company = firstNonEmpty(
    job.company,
    job.company_name,
    job.companyName,
    job.employerName,
    job.organisation
  )
  const location = firstNonEmpty(job.location, job.city, job.region, 'India')
  const description = firstNonEmpty(
    job.description,
    job.summary,
    job.details,
    job.desc,
    job.descriptionHtml
  )

  // Comprehensive apply URL extraction
  const applyUrl = ensureUrlLike(
    job.apply_url ||
      job.apply_link ||
      job.apply ||
      job.url ||
      job.jobUrl ||
      job.link ||
      job.share_link ||
      job.externalApplyLink ||
      job.applyUrl ||
      (job.apply_options && job.apply_options[0] && job.apply_options[0].link)
  )

  // Parse posted date
  let postedDate = new Date().toISOString()
  const dateField =
    job.posted_date ||
    job.posted_at ||
    job.datePosted ||
    job.date ||
    job.published_at ||
    job.publishedAt ||
    job.postedAt ||
    job.postedTime
  if (dateField) {
    const parsed = parseRelativeTime(dateField)
    postedDate = parsed || getDateISOOrNow(dateField)
  }

  return {
    title: cleanText(title),
    company: cleanText(company),
    location: cleanText(location),
    description: cleanText(description),
    apply_url: applyUrl,
    source: providerHint,
    external_id: buildExternalId(providerHint, job, applyUrl),
    posted_date: postedDate,
    salary: cleanText(job.salary || job.pay || job.compensation) || null,
    via: job.via || job.source || providerHint,
  }
}

// ========== ROUTING LOGIC ==========

function normalizeJob(job, errors) {
  try {
    if (!job || typeof job !== 'object') return null

    // Detect source
    const source = detectJobSource(job)

    // Route to appropriate normalizer
    switch (source) {
      case 'google_jobs':
        return normalizeFromGoogleJobs(job)
      case 'apify_linkedin':
        return normalizeFromApifyLinkedIn(job)
      case 'apify_indeed':
        return normalizeFromApifyIndeed(job)
      case 'apify_naukri':
        return normalizeFromApifyNaukri(job)
      case 'greenhouse':
      case 'lever':
      case 'generic':
      default:
        return normalizeGenericJob(job, source)
    }
  } catch (e) {
    errors.push({
      type: 'normalize_error',
      message: e.message,
      sample: JSON.stringify(job).slice(0, 500),
    })
    return null
  }
}

// ========== DATA EXTRACTION ==========

function extractJobsFromData(data, errors) {
  const jobs = []

  try {
    if (!data || typeof data !== 'object') return jobs

    // 1) Check for jobs_results array (SerpApi)
    if (data.jobs_results && Array.isArray(data.jobs_results)) {
      for (const job of data.jobs_results) {
        const normalized = normalizeJob(job, errors)
        if (normalized) jobs.push(normalized)
      }
      return jobs
    }

    // 2) Check for common container arrays
    const containers = ['jobs', 'results', 'data', 'items']
    for (const key of containers) {
      if (Array.isArray(data[key])) {
        for (const job of data[key]) {
          const normalized = normalizeJob(job, errors)
          if (normalized) jobs.push(normalized)
        }
        return jobs
      }
    }

    // 3) Check if data itself is an array
    if (Array.isArray(data)) {
      for (const job of data) {
        const normalized = normalizeJob(job, errors)
        if (normalized) jobs.push(normalized)
      }
      return jobs
    }

    // 4) Single job object
    const normalized = normalizeJob(data, errors)
    if (normalized) jobs.push(normalized)
  } catch (e) {
    errors.push({
      type: 'extraction_error',
      message: e.message,
      sample: JSON.stringify(data).slice(0, 500),
    })
  }

  return jobs
}

// ========== MAIN EXECUTION ==========

const allJobs = []
const errors = []

// Process all input items
for (const item of $input.all()) {
  const data = item.json
  const extracted = extractJobsFromData(data, errors)
  allJobs.push(...extracted)
}

// Validation: Require title, company, apply_url
const isValid = (j) => {
  return (
    j &&
    j.title &&
    j.title.length > 0 &&
    j.company &&
    j.company.length > 0 &&
    j.apply_url &&
    j.apply_url.length > 10
  ) // URLs should be at least 10 chars
}

const validJobs = allJobs.filter(isValid)

// De-duplication by (external_id)
const seen = new Set()
const uniqueJobs = []

for (const job of validJobs) {
  const key = job.external_id
  if (!seen.has(key)) {
    seen.add(key)
    uniqueJobs.push(job)
  }
}

// Log results
console.log(
  `Processed ${allJobs.length} jobs, ${validJobs.length} valid, ${uniqueJobs.length} unique`
)
if (errors.length > 0) {
  console.log(`Errors encountered: ${errors.length}`)
}

return [
  {
    json: {
      jobs: uniqueJobs,
      totalRaw: allJobs.length,
      totalValid: validJobs.length,
      totalUnique: uniqueJobs.length,
      duplicatesRemoved: validJobs.length - uniqueJobs.length,
      errors: errors.slice(0, 10), // Limit error array to prevent overflow
    },
  },
]

// Deduplicate jobs using title + company similarity
const data = $input.first().json;
const jobs = data.jobs || [];
const uniqueJobs = [];
const seenExternalIds = new Set();
const seenTitleCompany = new Set();

for (const job of jobs) {
  // Skip if external_id already seen
  if (seenExternalIds.has(job.external_id)) continue;

  // Create a normalized key for deduplication
  const normalizedTitle = (job.title || '').toLowerCase().trim()
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ');
  const normalizedCompany = (job.company || '').toLowerCase().trim()
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ');

  const key = `${normalizedTitle}_${normalizedCompany}`;

  if (!seenTitleCompany.has(key) && normalizedTitle.length > 0 && normalizedCompany.length > 0) {
    seenExternalIds.add(job.external_id);
    seenTitleCompany.add(key);
    uniqueJobs.push(job);
  }
}

return [{ 
  json: { 
    jobs: uniqueJobs, 
    totalBefore: jobs.length,
    totalAfter: uniqueJobs.length,
    duplicatesRemoved: jobs.length - uniqueJobs.length
  } 
}];

