// Log completion stats for this user

// Helper to safely get data from previous nodes (handles Arrays)
const getData = (nodeName) => {
  const nodeData = $node[nodeName];
  // Check if it's an array and has items
  if (Array.isArray(nodeData) && nodeData.length > 0) {
    return nodeData[0].json;
  }
  return {}; // Return empty object if node didn't run or has no data
};

// Access user data (handling array access safely)
const userNode = $node['Loop Over Each User'];
const userData = (Array.isArray(userNode) ? userNode[0] : userNode).json;

const userId = userData.user_id;
const userName = userData.name;

// Use array index [0] instead of .first()
const normalizeResult = getData('Normalize Job Format');
const dedupeResult = getData('Deduplicate Jobs');
const importResult = getData('Import to Database (with userId)');

const log = {
  timestamp: new Date().toISOString(),
  userId: userId,
  userName: userName,
  rawJobs: normalizeResult.totalRaw || 0,
  validJobs: normalizeResult.totalValid || 0,
  afterDedup: dedupeResult.totalAfter || 0,
  duplicatesRemoved: dedupeResult.duplicatesRemoved || 0,
  stored: importResult?.stats?.stored || 0,
  matchesCreated: importResult?.stats?.matchesCreated || 0,
  aiQueued: importResult?.stats?.aiQueued || 0,
  success: importResult?.success || false
};

console.log('User processing complete:', JSON.stringify(log, null, 2));

return [{ json: log }];

// Final summary of entire daily run
const allLogs = $input.all();

const summary = {
  timestamp: new Date().toISOString(),
  pipeline: 'daily-per-user-scraping',
  totalUsers: allLogs.length,
  totalJobsStored: allLogs.reduce((sum, item) => sum + (item.json.stored || 0), 0),
  totalMatchesCreated: allLogs.reduce((sum, item) => sum + (item.json.matchesCreated || 0), 0),
  totalAIQueued: allLogs.reduce((sum, item) => sum + (item.json.aiQueued || 0), 0),
  usersProcessed: allLogs.filter(item => item.json.success).length,
  usersFailed: allLogs.filter(item => !item.json.success).length,
  status: 'completed'
};

console.log('\n=== DAILY SCRAPING COMPLETE ===');
console.log(JSON.stringify(summary, null, 2));
console.log('================================\n');

return [{ json: summary }];
